#include &lt;stdio.h&gt;
#include &lt;string.h&gt;
#include &lt;sys/mman.h&gt;
#include &lt;unistd.h&gt;

int main() {
    // 1. Allocate Page-Aligned Memory
    // Using mmap instead of malloc because mprotect requires strict 4096-byte boundaries.
    size_t page_size = sysconf(_SC_PAGESIZE);
    void *mem = mmap(NULL, page_size, PROT_READ | PROT_WRITE, 
                     MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);

    // 2. The Machine Code Payload (x86_64 Assembly)
    // mov eax, 42  (0xB8 0x2A 0x00 0x00 0x00)
    // ret          (0xC3)
    unsigned char jitted_opcodes[] = { 
        0xB8, 0x2A, 0x00, 0x00, 0x00, 
        0xC3 
    };

    // 3. Inject the payload into the Writable RAM
    memcpy(mem, jitted_opcodes, sizeof(jitted_opcodes));

    // 4. The W^X Transition
    // Strip Write permissions, grant Execute permissions.
    if (mprotect(mem, page_size, PROT_READ | PROT_EXEC) == -1) {
        perror("mprotect failed");
        return 1;
    }

    // 5. Execution
    // Cast the raw memory address into a standard C function pointer
    int (*dynamic_func)() = mem;

    // The CPU physically jumps to the Heap and executes our opcodes
    int result = dynamic_func();

    printf("JIT Function Returned: %d\n", result);

    // Cleanup
    munmap(mem, page_size);
    return 0;
}

#include &lt;sys/mman.h&gt;
#include &lt;string.h&gt;

void run_jit_payload(void *mem, unsigned char *new_opcodes, int size) {
    // Engineer needs to update the JIT code dynamically during runtime
    mprotect(mem, 4096, PROT_READ | PROT_WRITE);

    // Overwrite old opcodes with new opcodes
    memcpy(mem, new_opcodes, size);

    // Switch back to Executable
    mprotect(mem, 4096, PROT_READ | PROT_EXEC);

    // Execute
    int (*func)() = mem;

    // BUG: On ARM processors, this randomly executes the OLD opcodes!
    func();
}

#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;unistd.h&gt;
#include &lt;seccomp.h&gt;

void apply_security_sandbox() {
    // 1. Initialize filter: Default action is to KILL the process
    scmp_filter_ctx ctx = seccomp_init(SCMP_ACT_KILL);
    if (ctx == NULL) exit(EXIT_FAILURE);

    // 2. Allow exactly the syscalls required for normal operation.
    // A web worker only needs to read sockets, write sockets, and close them.
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(read), 0);
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(write), 0);
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(close), 0);
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(exit_group), 0);

    // Elite addition: Only allow 'open' if it is strictly READ-ONLY.
    // This uses BPF argument filtering to inspect the specific flags passed to open().
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(openat), 1,
                     SCMP_CMP(2, SCMP_CMP_EQ, O_RDONLY));

    // 3. Load the BPF bytecode into the Kernel
    if (seccomp_load(ctx) < 0) {
        perror("Seccomp load failed");
        exit(EXIT_FAILURE);
    }

    seccomp_release(ctx); // Free user-space config memory
    printf("Sandbox active. Process is now mathematically contained.\n");
}

